def kmp_table(w):
    T = [0] * len(w)
    pos = 1
    cnd = 0
    while pos < len(w):
        if w[pos] == w[cnd]:
            T[pos] = cnd + 1
            pos += 1
            cnd += 1
        elif cnd > 0:
            cnd = T[cnd-1]
        else:
            pos += 1
    return T

def kmp_search(s, w):
    T = kmp_table(w)
    pos = 0
    i = 0
    result = []
    while i < len(s):
        if w[pos] == s[i]:
            i += 1
            pos += 1
            if pos == len(w):
                result.append(i - pos)
                pos = T[pos-1]
        elif pos > 0:
            pos = T[pos-1]
        else:
            i += 1
    return result
